45	export function validateScoreConfig<Chord, Section extends string | number>(config: ScoreConfig<Chord, Section>) {
46	  const issues: string[] = [];
47	  const positiveInteger = (value: number | undefined, label: string) => {
48	    if (value === undefined || !Number.isInteger(value) || value <= 0) issues.push(`${label} must be a positive integer`);
49	  };
50	
51	  if (!Number.isFinite(config.bpm) || config.bpm <= 0) issues.push('bpm must be a positive finite number');
52	  positiveInteger(config.stepsPerBar, 'stepsPerBar');
53	  if (!config.chords.length) issues.push('chords must not be empty');
54	  positiveInteger(config.barsPerChord ?? 1, 'barsPerChord');
